{
  "family": "Retro-Claisen Reaction",
  "candidate": {
    "substrate_smiles": [
      "CCC(=O)C(C)C(=O)OCC"
    ],
    "product_smiles": [
      "CCC(=O)C",
      "CC(=O)OCC"
    ],
    "optional_reagent_smiles": [
      "[OH-].[Na+]"
    ],
    "rationale": "This example shows the base-catalyzed cleavage of ethyl 2-methyl-3-oxopentanoate, a simple acyclic beta-keto ester. The reaction breaks the C-C bond between the alpha-carbon and the ketone carbonyl, yielding butan-2-one and ethyl acetate. This is a classic textbook illustration of the retro-Claisen reaction, demonstrating the cleavage of a 1,3-dicarbonyl system into two simpler carbonyl compounds.",
    "collision_avoidance_note": "The structure is a simple, acyclic beta-keto ester, avoiding complex ring systems or functional groups that could overlap with other named reactions. The cleavage is the defining feature, distinguishing it from forward Claisen condensations or other carbonyl reactions like aldol or Michael additions. The use of a simple alkyl-substituted substrate avoids arene-related collisions."
  }
}
